}

Method.Source:
/// <summary>
/// Extension of the <c>init</c> method for the ETGSPAIN model.
/// </summary>
/// <remarks>This code is used to show or hide features in Spanish companies.</remarks>    
public void init()
{
    next init();
    NoYesId currentCompanyIsSpanishCompany  = CurrentCompanyIsSpanishCompany();

    this.design().controlName(formControlStr(LedgerParameters, ETGSPAINFinancialDimensions)).visible(currentCompanyIsSpanishCompany);

    this.design().controlName(formControlStr(LedgerParameters, ETGSPAINFinancialDimensions_ETGSPAINFinDimApplication)).visible(currentCompanyIsSpanishCompany);
    this.design().controlName(formControlStr(LedgerParameters, ETGSPAINFinancialDimensions_ETGSPAINFinDimContract)).visible(currentCompanyIsSpanishCompany);
    this.design().controlName(formControlStr(LedgerParameters, ETGSPAINFinancialDimensions_ETGSPAINFinDimOperation)).visible(currentCompanyIsSpanishCompany);

}
